struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    DataResult result;

    // 1. Create a buffer_adaptor from the input span
    // Note: Need to create a non-const copy since buffer_adaptor expects non-const reference
    std::span<uint8_t> non_const_buffer = const_cast<uint8_t*>(buffer.data()), buffer.size());
    hexi::buffer_adaptor<std::span<uint8_t>> adaptor(non_const_buffer);

    // 2. Use buffer_adaptor's preview function to read the first byte (data_type) without advancing read pointer
    uint8_t data_type;
    adaptor.preview(&data_type, sizeof(uint8_t));
    result.data_type = data_type;

    // 3. Calculate the total required bytes: 1 (data_type) + 4 (item_count) + (item_count * sizeof(item))
    uint32_t item_count;
    adaptor.read(&item_count, sizeof(uint32_t)); // Advance past data_type to read item_count

    // Calculate total bytes needed for items
    size_t total_item_bytes = item_count * (result.data_type == 0 ? sizeof(uint32_t) : sizeof(float));

    // 4. Check if the buffer has enough data using buffer_adaptor's size() function
    if (adaptor.size() < total_item_bytes) {
        // Not enough data, return empty result
        return result;
    }

    // 5. If there's enough data, read the item_count and then the items
    // We've already read data_type and item_count, now read the actual items
    if (result.data_type == 0) {
        // Integers case
        result.int_items.resize(item_count);
        adaptor.read(result.int_items.data(), total_item_bytes);
    } else {
        // Floats case
        result.float_items.resize(item_count);
        adaptor.read(result.float_items.data(), total_item_bytes);
    }

    return result;
}
