#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator instance with uint64_t type
    hexi::block_allocator<uint64_t, element_count> allocator;

    // Demonstrate initial state: free list contains element_count blocks
    // (created during construction via initialize_free_list())

    // Allocate one block - this will remove the head of the free list
    uint64_t* ptr1 = allocator.allocate();

    // Deallocate the block - this will push it back to the head of the free list
    allocator.deallocate(ptr1);

    // Allocate multiple blocks to show LIFO behavior
    uint64_t* ptr2 = allocator.allocate();
    uint64_t* ptr3 = allocator.allocate();

    // Deallocate in reverse order to demonstrate LIFO (Last-In-First-Out)
    // ptr3 was allocated last, so it becomes the new head when deallocated
    allocator.deallocate(ptr3);

    // ptr2 was allocated before ptr3, so it becomes the head after ptr3 is deallocated
    allocator.deallocate(ptr2);

    // Show that when free list is empty, new blocks are allocated from the system
    // (This happens when we exceed the initial element_count)
    for (size_t i = 0; i < element_count + 2; ++i) {
        uint64_t* ptr = allocator.allocate();
        allocator.deallocate(ptr);
    }

    // The allocator automatically manages the free list through:
    // - allocate(): calls pop() to get the head block, or allocates new if empty
    // - deallocate(): calls push() to add the block back to the head of the free list
}
```

**Explanation:**

This implementation demonstrates the internal free list management by:

1. **Creating the allocator**: The constructor initializes the free list with `element_count` blocks using `initialize_free_list()`

2. **Single allocation/deallocation**: Shows how `allocate()` removes the head block (via implicit `pop()`) and `deallocate()` adds it back to the head (via implicit `push()`)

3. **Multiple allocations**: Demonstrates that blocks are allocated from the free list in LIFO order

4. **Free list exhaustion**: Shows that when the pre-allocated blocks are exhausted, the allocator falls back to system allocation

The key insight is that `allocate()` internally uses `pop()` to remove the head of the free list, and `deallocate()` uses `push()` to add blocks back to the head, maintaining a LIFO structure.

