void write_container_to_stream(hexi::pmc::binary_stream_writer& writer, const std::vector<uint32_t>& container) {
    // Write the size of the vector as a prefix using native endian
    writer << container.size();

    // Write the container elements using the stream's operator<<
    for (const auto& element : container) {
        writer << element;
    }
}

std::vector<uint32_t> read_container_from_stream(hexi::pmc::binary_stream_reader& reader) {
    std::vector<uint32_t> result;

    // Read the count first using the stream's operator>>
    uint32_t count;
    reader >> count;

    // Resize the vector based on the count
    result.resize(count);

    // Read each element into the vector using the stream's operator>>
    for (auto& element : result) {
        reader >> element;
    }

    return result;
}
```

