using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    // Create a buffer to hold the encoded data
    std::vector<std::byte> buffer;

    // Create a buffer_adaptor for the buffer
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Create a binary_stream_writer using the buffer_adaptor
    hexi::pmc::binary_stream_writer stream_writer(adaptor);

    // Use the writer's put method with the varint encoding adaptor
    stream_writer.put(hexi::pmc::varint<T>(value));

    // Return the number of bytes written
    return buffer.size();
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    T value;

    // Use the operator>> with the varint adaptor to decode
    reader >> hexi::pmc::varint<T>(value);

    // Return the decoded value
    return value;
}

