struct CompactPacket {
    uint32_t packet_id;
    std::vector<std::string> tags;
    std::string data;
};

std::vector<uint8_t> serialize_compact_packet(const CompactPacket& packet) {
    // Create a buffer to hold the serialized data
    std::vector<uint8_t> buffer;

    // Create a buffer_adaptor for the vector
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(buffer);

    // Create a binary_stream object with the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Serialize packet_id as a raw 32-bit integer
    stream << packet.packet_id;

    // Use prefixed_varint adaptor for tags vector
    stream << hexi::prefixed_varint(packet.tags);

    // Use prefixed_varint adaptor for data string
    stream << hexi::prefixed_varint(packet.data);

    return buffer;
}

CompactPacket deserialize_compact_packet(const std::span<const uint8_t> buffer) {
    CompactPacket packet;

    // Create a buffer_adaptor from the input span
    // Note: Need to create a non-const copy since buffer_adaptor requires non-const reference
    std::vector<uint8_t> non_const_buffer(buffer.begin(), buffer.end());
    hexi::buffer_adaptor<std::vector<uint8_t>> adaptor(non_const_buffer);

    // Create a binary_stream object with the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    // Deserialize packet_id as a raw 32-bit integer
    stream >> packet.packet_id;

    // Use prefixed_varint adaptor to read tags vector
    stream >> hexi::prefixed_varint(packet.tags);

    // Use prefixed_varint adaptor to read data string
    stream >> hexi::prefixed_varint(packet.data);

    return packet;
}
